            self.ws = self.wb[sheet_name] if sheet_name in self.wb.sheetnames else self.wb.active
            self.headers_written = True
        else:
            self.wb = openpyxl.Workbook()
            self.ws = self.wb.active
            self.ws.title = sheet_name
            self.headers_written = False

    def write_headers(self, headers: list):
        if not self.headers_written:
            self.ws.append(headers)
            self.headers_written = True
            self.wb.save(self.filepath)

    def append_row(self, row_data: list):
        self.ws.append(row_data)
        self._unflushed_rows += 1
        if self._unflushed_rows >= _AUTO_FLUSH_EVERY:
            self.flush()

    def flush(self):
        if self._unflushed_rows > 0:
            self.wb.save(self.filepath)
            self._unflushed_rows = 0

    def close(self):
        self.flush()


class ReportExcelWriter:
    def __init__(self, filepath: Path):
        self.filepath = filepath
        self.wb = openpyxl.Workbook()

        self.ws_mismatch = self.wb.active
        self.ws_mismatch.title = "Mismatches"

        self.ws_missing = self.wb.create_sheet("Missing Data")
        self.ws_passed  = self.wb.create_sheet("Passed")

        self.headers_written = False
        self._unflushed_rows = 0

    def write_headers(self, headers: list):
        if not self.headers_written:
            self.ws_mismatch.append(headers)
            self.ws_missing.append(headers)
            self.ws_passed.append(headers)
            self.headers_written = True
            self.wb.save(self.filepath)

    def append_row(self, row_data: list, status: str):
        if status == "Mismatch":
            self.ws_mismatch.append(row_data)
        elif status == "Missing Data":
            self.ws_missing.append(row_data)
        elif status == "Passed":
            self.ws_passed.append(row_data)

        self._unflushed_rows += 1
        if self._unflushed_rows >= _AUTO_FLUSH_EVERY:
            self.flush()

    def flush(self):
        if self._unflushed_rows > 0:
            self.wb.save(self.filepath)
            self._unflushed_rows = 0

    def close(self):
        self.flush()
